//! LoongArch backend implementing the `robustone-isa` `ArchitectureBackend` trait.

use robustone_core::ir::{ArchitectureId, RegisterId};
use robustone_core::types::error::DisasmError;
use robustone_isa::{
    Access, AliasPolicy, DecodeProfile, FeatureSet, ImmediateKind, ImmediateTransform,
    InstructionGroup, InstructionRead, InstructionSpec, RenderDialect, RenderPolicy,
};

// ============================================================================
// LoongArch types — generated by define_arch!
// ============================================================================

robustone_isa_macros::define_arch! {
    pub arch LoongArch {
        word = u32;
        endian = little;
        instruction_length = fixed(4);
        modes {
            LA32 = "loongarch32";
            LA64 = "loongarch64";
        };
        features: u16 {
            BASE       = 0;
            LA64       = 1;
            FLOAT32    = 2;
            FLOAT64    = 3;
            PRIVILEGED = 4;
            ATOMIC     = 5;
            LSX        = 6;
            LASX       = 7;
            LVZ        = 8;
            LBT        = 9;
        };
        registers = loongarch_registers;
        formats = loongarch_formats;
        specs = loongarch_specs;
        render = LoongArchRenderPolicy;
        backend_impl {
            field = LoongArchField;
            register_class = LoongArchRegisterClass;
            architecture_id = ArchitectureId::LoongArch;
            read_instruction = loongarch_read_instruction;
            lookup = loongarch_lookup;
            lower_register = loongarch_lower_register;
            render_policy = loongarch_render_policy;
            apply_aliases = crate::backend::aliases::apply_aliases;
        }
    }
}

impl LoongArchBackend {
    /// Production profile for LA64 (base integer, branch, memory).
    pub fn la64_base() -> DecodeProfile<Self> {
        DecodeProfile {
            mode: LoongArchMode::LA64,
            features: LoongArchFeature::BASE | LoongArchFeature::LA64,
            render_dialect: RenderDialect::Canonical,
            alias_policy: AliasPolicy::None,
        }
    }

    /// Production profile for LA32 (base integer).
    pub fn la32_base() -> DecodeProfile<Self> {
        DecodeProfile {
            mode: LoongArchMode::LA32,
            features: LoongArchFeature::BASE,
            render_dialect: RenderDialect::Canonical,
            alias_policy: AliasPolicy::None,
        }
    }

    /// Test profile with all features and pseudo-instruction aliases enabled.
    pub fn capstone_test_la64() -> DecodeProfile<Self> {
        DecodeProfile {
            mode: LoongArchMode::LA64,
            features: LoongArchFeature::all_supported_for_tests(),
            render_dialect: RenderDialect::Assembler,
            alias_policy: AliasPolicy::PreferPseudo,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LoongArchField {
    Rd,
    Rj,
    Rk,
    Ra,
    Cd,
    I8,
    Si12,
    Ui12,
    Si14,
    Si16,
    Si20,
    Si21,
    Ui5,
    Ui6,
    MsbW,
    LsbW,
    MsbD,
    LsbD,
    I26Lo,
    I26Hi,
    Code,
}

robustone_isa_macros::define_registers! {
    arch = LoongArch;
    bank Gpr  { count = 32; base_id = 0;   prefix = "$r"; }
    bank Fpr  { count = 32; base_id = 32;  prefix = "$f"; }
    bank Xr   { count = 32; base_id = 64;  prefix = "$x"; }
    bank Fcc  { count = 8;  base_id = 96; }
    bank Scr  { count = 4;  base_id = 104; }
    bank Fcsr { count = 4;  base_id = 108; }
}

// ============================================================================
// Format specs
// ============================================================================

robustone_isa_macros::define_formats! {
    arch = LoongArch; extern_fields;
    fields { Cd; Code; I26Hi; I26Lo; I8; LsbD; LsbW; MsbD; MsbW; Ra; Rd; Rj; Rk; Si12; Si14; Si16; Si20; Si21; Ui12; Ui5; Ui6; };
    format FMT_R2 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
    };
    format FMT_R3 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        rk: bits(10, 5) as Rk,
    };
    format FMT_R3I2 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        rk: bits(10, 5) as Rk,
        sa2: bits(15, 2) as Ui5,
    };
    format FMT_R3I3 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        rk: bits(10, 5) as Rk,
        ui3: bits(15, 3) as Ui5,
    };
    format FMT_R4 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        rk: bits(10, 5) as Rk,
        ra: bits(15, 5) as Ra,
    };
    format FMT_FCMP {
        cd: bits(0, 3) as Cd,
        fj: bits(5, 5) as Rj,
        fk: bits(10, 5) as Rk,
    };
    format FMT_CSR {
        rd: bits(0, 5) as Rd,
        csr: bits(10, 14) as Si14,
    };
    format FMT_CSRXCHG {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        csr: bits(10, 14) as Si14,
    };
    format FMT_INVTLB {
        imm: bits(0, 5) as Ui5,
        rj: bits(5, 5) as Rj,
        rk: bits(10, 5) as Rk,
    };
    format FMT_R2I8 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        i8: bits(10, 8) as I8,
    };
    format FMT_R2I12 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        si12: bits(10, 12) as Si12,
    };
    format FMT_R2I14 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        si14: bits(10, 14) as Si14,
    };
    format FMT_R2I16 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        si16: bits(10, 16) as Si16,
    };
    format FMT_1RI21 {
        rd: bits(0, 5) as Rd,
        si21: bits(5, 21) as Si21,
    };
    format FMT_I26 {
        i26_lo: bits(0, 16) as I26Lo,
        i26_hi: bits(16, 10) as I26Hi,
    };
    format FMT_R1 {
        rd: bits(0, 5) as Rd,
    };
    format FMT_NONE {};
    format FMT_BJ {
        si16: bits(10, 16) as Si16,
    };
    format FMT_R1I16_BJ {
        rj: bits(5, 5) as Rj,
        si16: bits(10, 16) as Si16,
    };
    format FMT_I15 {
        code: bits(0, 15) as Code,
    };
    format FMT_R2I5 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        ui5: bits(10, 5) as Ui5,
    };
    format FMT_R2I6 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        ui6: bits(10, 6) as Ui6,
    };
    format FMT_R2I3 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        ui3: bits(10, 3) as Ui5,
    };
    format FMT_R2I4 {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        ui4: bits(10, 4) as Ui5,
    };
    format FMT_BSTR_W {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        msb: bits(16, 5) as MsbW,
        lsb: bits(10, 5) as LsbW,
    };
    format FMT_BSTR_D {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        msb: bits(16, 6) as MsbD,
        lsb: bits(10, 6) as LsbD,
    };
    format FMT_1RI20 {
        rd: bits(0, 5) as Rd,
        si20: bits(5, 20) as Si20,
    };
    format FMT_R2I12_U {
        rd: bits(0, 5) as Rd,
        rj: bits(5, 5) as Rj,
        ui12: bits(10, 12) as Ui12,
    };
    format FMT_LDPTE {
        rj: bits(5, 5) as Rj,
        seq: bits(10, 8) as I8,
    }
}

