// ============================================================================
// Backend implementation
// ============================================================================

fn loongarch_read_instruction(bytes: &[u8]) -> Result<InstructionRead<u32>, DisasmError> {
    if bytes.len() < 4 {
        return Err(DisasmError::decode_failure(
            robustone_core::types::error::DecodeErrorKind::NeedMoreBytes,
            Some("loongarch".to_string()),
            "need at least 4 bytes",
        ));
    }
    let word = u32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]);
    Ok(InstructionRead {
        raw: word,
        length: 4,
    })
}

fn loongarch_lookup(
    word: u32,
    profile: &DecodeProfile<LoongArchBackend>,
) -> Option<&'static InstructionSpec<LoongArchBackend>> {
    let tables: &[&[InstructionSpec<LoongArchBackend>]] = &[LOONGARCH_BASE_SPECS, VECTOR_SPECS];
    tables
        .iter()
        .flat_map(|t| t.iter())
        .find(|spec| {
            (word & spec.pattern().mask) == spec.pattern().value
                && spec.modes().matches(profile.mode)
                && profile.features.contains(spec.features())
        })
}

fn loongarch_lower_register(
    class: LoongArchRegisterClass,
    raw: u32,
    _profile: &DecodeProfile<LoongArchBackend>,
) -> RegisterId {
    match lower_register(class, raw) {
        Ok(id) => RegisterId::loongarch(id),
        Err(_) => RegisterId::loongarch(raw),
    }
}

fn loongarch_render_policy(
    profile: &DecodeProfile<LoongArchBackend>,
) -> RenderPolicy<LoongArchBackend> {
    RenderPolicy::new(profile.render_dialect, profile.alias_policy)
}

